class Solution {
public:
    bool isIdealPermutation(vector<int>& nums) {
        int n=nums.size();
        for(int i=0;i<n;i++){
            if(nums[i]-i>1) return false;
            if(i+2<n && nums[i]>nums[i+2]) return false;
        }
        return true;
    }
};

